import{_ as e,c as r,o as a,a4 as t}from"./chunks/framework.HaEZziQ1.js";const f=JSON.parse('{"title":"浏览器兼容性问题解决","description":"","frontmatter":{},"headers":[],"relativePath":"Document/代码浏览器兼容问题/浏览器兼容性问题解决.md","filePath":"Document/代码浏览器兼容问题/浏览器兼容性问题解决.md","lastUpdated":1709668918000}'),i={name:"Document/代码浏览器兼容问题/浏览器兼容性问题解决.md"},o=t('<h1 id="浏览器兼容性问题解决" tabindex="-1">浏览器兼容性问题解决 <a class="header-anchor" href="#浏览器兼容性问题解决" aria-label="Permalink to &quot;浏览器兼容性问题解决&quot;">​</a></h1><ul><li>如何发现问题：QuirksMode、 CanlUse</li><li>如何解决问题：BrowserHacks、ES5Shim、ES6Shim</li><li>如何把事做绝：渐进增强，Modernizr、Feature.js</li></ul><h2 id="发现兼容性问题的工具网站" tabindex="-1">发现兼容性问题的工具网站 <a class="header-anchor" href="#发现兼容性问题的工具网站" aria-label="Permalink to &quot;发现兼容性问题的工具网站&quot;">​</a></h2><h3 id="quirksmode-兼容性列表" tabindex="-1">QuirksMode -- 兼容性列表 <a class="header-anchor" href="#quirksmode-兼容性列表" aria-label="Permalink to &quot;QuirksMode -- 兼容性列表&quot;">​</a></h3><p>网址：<a href="https://www.quirksmode.org/compatibility.html" target="_blank" rel="noreferrer">Compatibility overview (quirksmode.org)</a></p><p>标准：<a href="https://quirks.spec.whatwg.org/" target="_blank" rel="noreferrer">怪癖模式标准 (whatwg.org)</a></p><h3 id="canluse-查询js特性-css属性html5等代码浏览器支持和兼容性情况" tabindex="-1">CanlUse -- 查询JS特性/CSS属性HTML5等代码浏览器支持和兼容性情况 <a class="header-anchor" href="#canluse-查询js特性-css属性html5等代码浏览器支持和兼容性情况" aria-label="Permalink to &quot;CanlUse -- 查询JS特性/CSS属性HTML5等代码浏览器支持和兼容性情况&quot;">​</a></h3><p>网址：<a href="https://caniuse.com/" target="_blank" rel="noreferrer">Can I use... Support tables for HTML5, CSS3, etc</a></p><p>中国的每种浏览器的市场份额，和每种浏览器的版本是否兼容代码</p><p>浏览器的对比功能...</p><h2 id="解决浏览器兼容性问题-适配浏览器" tabindex="-1">解决浏览器兼容性问题（适配浏览器） <a class="header-anchor" href="#解决浏览器兼容性问题-适配浏览器" aria-label="Permalink to &quot;解决浏览器兼容性问题（适配浏览器）&quot;">​</a></h2><h3 id="browserhacks" tabindex="-1">BrowserHacks <a class="header-anchor" href="#browserhacks" aria-label="Permalink to &quot;BrowserHacks&quot;">​</a></h3><p>网址：<a href="http://browserhacks.com/" target="_blank" rel="noreferrer">Browserhacks</a></p><p>各个浏览器的兼容性CSS前缀，和JavaScript代码如何去兼容各种浏览器</p><h3 id="shim" tabindex="-1">Shim <a class="header-anchor" href="#shim" aria-label="Permalink to &quot;Shim&quot;">​</a></h3><p>什么是Shim？</p><p>对应不支持的代码特性，通过修改或添加老的浏览器的原型方法，使它拥有那些方法</p><h4 id="es5shim" tabindex="-1">ES5Shim <a class="header-anchor" href="#es5shim" aria-label="Permalink to &quot;ES5Shim&quot;">​</a></h4><p>网址：<a href="https://snyk.io/advisor/npm-package/es5-shim" target="_blank" rel="noreferrer">es5-shim - npm Package Health Analysis | Snyk</a></p><p>GitHub：<a href="https://github.com/es-shims/es5-shim" target="_blank" rel="noreferrer">es-shims/es5-shim: ECMAScript 5 compatibility shims for legacy (and modern) JavaScript engines (github.com)</a></p><h4 id="es6shim" tabindex="-1">ES6Shim <a class="header-anchor" href="#es6shim" aria-label="Permalink to &quot;ES6Shim&quot;">​</a></h4><p>网址：<a href="https://cdnjs.com/libraries/es6-shim" target="_blank" rel="noreferrer">es6-shim - Libraries - cdnjs - The #1 free and open source CDN built to make life easier for developers</a></p><p>GitHub：<a href="https://github.com/es-shims/es6-shim/" target="_blank" rel="noreferrer">es-shims/es6-shim: ECMAScript 6 compatibility shims for legacy JS engines (github.com)</a></p><h4 id="es7shim" tabindex="-1">ES7Shim <a class="header-anchor" href="#es7shim" aria-label="Permalink to &quot;ES7Shim&quot;">​</a></h4><p>CDN：<a href="https://www.bootcdn.cn/es7-shim/" target="_blank" rel="noreferrer">es7-shim (v6.0.0) - ECMAScript 7 compatibility shims for legacy JavaScript engines | BootCDN - Bootstrap 中文网开源项目免费 CDN 加速服务</a></p><h2 id="渐进增强" tabindex="-1">渐进增强 <a class="header-anchor" href="#渐进增强" aria-label="Permalink to &quot;渐进增强&quot;">​</a></h2><h3 id="modernizr" tabindex="-1">Modernizr <a class="header-anchor" href="#modernizr" aria-label="Permalink to &quot;Modernizr&quot;">​</a></h3><p>官网：<a href="https://modernizr.com/" target="_blank" rel="noreferrer">Modernizr: the feature detection library for HTML5/CSS3</a></p><hr><p>参考文章：<a href="https://www.cnblogs.com/JoannaQ/p/3281841.html" target="_blank" rel="noreferrer">Modernizr的介绍和使用 - Joanna Qian - 博客园 (cnblogs.com)</a></p><p>传统浏览器目前不会被完全取代，令你难以将最新的 CSS3 或 HTML5 功能嵌入你的网站。</p><p>Modernizr 正是为解决这一难题应运而生，作为一个开源的 JavaScript 库，Modernizr 检测浏览器对 CSS3 或 HTML5 功能支持情况。 Modernizr 并非试图添加老版本浏览器不支持的功能，而是令你通过创建可选风格配置修改页面设计。 它也可以通过加载定制的脚本来模拟老版本浏览器不支持的功能。</p><p>Modernizr是一个开源的JS库，它使得那些基于访客浏览器的不同（指对新标准支持性的差异）而开发不同级别体验的设计师的工作变得更为简单。它使得设计师可以在支持<a href="http://www.mhtml5.com/" target="_blank" rel="noreferrer">HTML5</a>和CSS3的浏览器中充分利用<a href="http://www.mhtml5.com/" target="_blank" rel="noreferrer">HTML5</a>和CSS3的特性进行开发，同时又不会牺牲其他不支持这些新技术的浏览器的控制。</p><p>当你在网页中嵌入Modernizr的脚本时，它会检测当前浏览器是否支持CSS3的特性，比如 @font-face、border-radius、 border-image、box-shadow、rgba() 等，同时也会检测是否支持<a href="http://www.mhtml5.com/" target="_blank" rel="noreferrer">HTML5</a>的 特性——比如audio、video、本地储存、和新的 input 标签的类型和属性等。在获取到这些信息的基础上，你可以在那些支持这些功能的浏览器上使用它们，来决定是否创建一个基于JS的 fallback，或者对那些不支持的浏览器进行简单的优雅降级。另外，Modernizr还可以令IE支持对<a href="http://www.mhtml5.com/" target="_blank" rel="noreferrer">HTML5</a>的元素应用CSS样式，这样开发者就可以立即使用这些更富有语义化的标签了。</p><hr><h4 id="基于modenizr-做渐进增强步骤" tabindex="-1">基于Modenizr 做渐进增强步骤 <a class="header-anchor" href="#基于modenizr-做渐进增强步骤" aria-label="Permalink to &quot;基于Modenizr 做渐进增强步骤&quot;">​</a></h4><ul><li>下载安装：modenizr <ul><li>下载地址：<a href="https://modernizr.com/download?setclasses" target="_blank" rel="noreferrer">Modernizr Download Builder</a></li></ul></li><li>获取配置：自定义构建 <ul><li>下载地址里面有添加构建需要支持的方法和标签配置</li></ul></li><li>生成构建：命令行用法 <ul><li>选择完需要构建的配置后，点击右上角粉红色按钮：”BUILD“</li></ul></li><li>引人脚本：直接页面引用 <ul><li>”BUILD“构建后，复制或者下载生成的代码</li></ul></li><li>使用方法：JS + CSS <ul><li>在项目种引入使用</li></ul></li></ul><h3 id="feature-js" tabindex="-1">Feature.js <a class="header-anchor" href="#feature-js" aria-label="Permalink to &quot;Feature.js&quot;">​</a></h3><p>GitHub：<a href="https://github.com/arielsalminen/feature.js" target="_blank" rel="noreferrer">arielsalminen/feature.js</a></p><p>官网：<a href="https://featurejs.com/" target="_blank" rel="noreferrer">Feature.js (featurejs.com)</a></p><hr><p>文章参考：<a href="https://www.mianshigee.com/project/feature-js/" target="_blank" rel="noreferrer">Feature.js是一款轻量级的浏览器特性检测JavaScript库插件-面圈网 (mianshigee.com)</a></p><p>Feature.js是一款轻量级的浏览器特性检测JavaScript库插件。该插件运行速度快，使用简单，文件只有1kb大小。通过Feature.js你可以检测客户浏览器是否支持某些特性，并针对这些特性编写代码。</p>',43),s=[o];function l(h,n,m,c,p,d){return a(),r("div",null,s)}const b=e(i,[["render",l]]);export{f as __pageData,b as default};
